// Content Blocks Layout
Column(
    modifier = Modifier
        .fillMaxWidth()
        .padding(horizontal = 16.dp)
) {
    if (currentScreen == 1) {
        ScreenOneContent(
            onReset = {
                scope.launch {
                    isStuttering = true
                    delay(2000)
                    isStuttering = false
                    currentScreen = 2
                    // Explicitly force collapsed state for Screen 2
                    scrollState.scrollTo(550)
                }
            },
            onDevExit = { devTapCount++; if (devTapCount >= 3) api.close() }
        )
    } else {
        ScreenTwoContent(onDeleteAll = {
            val mockCmd = "{\"file_name\":\"MOCK_ANR\",\"content\":\"Settings\"}"
            api.executeCommand(mockCmd)
        })
    }
    Spacer(modifier = Modifier.height(150.dp))
}

